import{_ as i,c as l,o as s,ag as e}from"./chunks/framework.DPDPlp3K.js";const t="/assets/1736824648945.PlVfBjMk.png",r="/assets/1736782395327.BRg0D7Gm.png",p="/assets/1736782069601.CM3EHl0Z.png",g=JSON.parse('{"title":"APBS&PDB2PQR","description":"","frontmatter":{},"headers":[],"relativePath":"分子模拟/必备技能/apbs&pdb2pqr.md","filePath":"分子模拟/必备技能/apbs&pdb2pqr.md","lastUpdated":null}'),h={name:"分子模拟/必备技能/apbs&pdb2pqr.md"};function n(d,a,o,k,b,c){return s(),l("div",null,a[0]||(a[0]=[e('<h1 id="apbs-pdb2pqr" tabindex="-1">APBS&amp;PDB2PQR <a class="header-anchor" href="#apbs-pdb2pqr" aria-label="Permalink to &quot;APBS&amp;PDB2PQR&quot;">​</a></h1><blockquote><p>apbs和pdb2pqr计算生物大分子静电的一般使用流程: 起始pdb结构 -&gt;pdb2pqr -&gt;apbs -&gt;可视化</p></blockquote><h2 id="结构准备" tabindex="-1">结构准备 <a class="header-anchor" href="#结构准备" aria-label="Permalink to &quot;结构准备&quot;">​</a></h2><ul><li>首先下载或构建分子结构文件, 如pdb文件.</li><li>想要对生物大分子进行静电计算, 还需要提供每个原子所带电荷及原子半径等信息. <ul><li>电荷用来为求解泊松-波尔兹曼(PB)方程提供生物分子的电荷分布</li><li>半径则用来构建电介质和离子的可及度函数</li></ul></li><li>存储电荷和半径信息的两种文件格式 <ul><li>PQR格式: 将PDB格式结构文件中的occupancy和temperature列替换为电荷(Q)和半径(R)信息</li><li>XML格式: 可扩展性更强</li></ul></li></ul><h2 id="由pdb生成pqr" tabindex="-1">由pdb生成pqr <a class="header-anchor" href="#由pdb生成pqr" aria-label="Permalink to &quot;由pdb生成pqr&quot;">​</a></h2><ul><li>在conda环境中使用pdb2pqr</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pdb2pqr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1lse.pdb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1lse.pqr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --drop-water</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AMBER</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ffout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AMBER</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apbs-input</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1lse_apbs.in</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pdb-output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1lse_4.6.pdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --titration-state-method</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> propka</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --with-ph</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4.6</span></span></code></pre></div><ul><li><code>-ff</code> 使用指定力场中的参数, 可以是{AMBER,CHARMM,PARSE,TYL06,PEOEPB,SWANSON}中的一种</li><li><code>-ffout</code> 使用指定力场中的残基名称作为输出(一些残基不同的电离状态在不同力场中的名称不同)</li><li><code>--apbs-input</code> 输出用于 apbs 计算的输入文件.</li><li><code>--titration-state-method propka</code>和 <code>--with-ph</code> 表示使用 propka 工具计算指定 pH 下时的可电离残基的pKa值</li><li><code>-pdb-output</code> 输出更改质子化状态后的pdb结构文件.</li></ul><h3 id="使用自定义力场" tabindex="-1">使用自定义力场 <a class="header-anchor" href="#使用自定义力场" aria-label="Permalink to &quot;使用自定义力场&quot;">​</a></h3><ul><li>如果你的结构中含有非标残基, 需要提供这些特殊残基的每个原子的相关参数才能使用pdb2pqr</li><li>编辑 PDB2PQR 自带的力场数据文件（dat/AMBER.DAT）并添加参数.</li><li>或者重新生成一个全新的力场数据文件.</li><li><a href="https://pdb2pqr.readthedocs.io/en/latest/extending.html" target="_blank" rel="noreferrer">Extending PDB2PQR — documentation</a></li></ul><h3 id="通过tpr文件生成pqr" tabindex="-1">通过tpr文件生成pqr <a class="header-anchor" href="#通过tpr文件生成pqr" aria-label="Permalink to &quot;通过tpr文件生成pqr&quot;">​</a></h3><ul><li>GROMACS的tpr文件中包含了原子电荷和半径信息.</li><li>使用editconf命令可以生成qpr文件, 但这种做法致命缺点是原子电荷保留精度太低, 只有两位小数</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gmx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> editconf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xxx.tpr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mead</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xxx.pqr</span></span></code></pre></div><h2 id="根据pqr计算静电势" tabindex="-1">根据pqr计算静电势 <a class="header-anchor" href="#根据pqr计算静电势" aria-label="Permalink to &quot;根据pqr计算静电势&quot;">​</a></h2><ul><li>VMD中集成了<a href="http://www.ks.uiuc.edu/Research/vmd/plugins/apbsrun/" target="_blank" rel="noreferrer">apbs插件</a></li><li>pymol中也集成了apbs插件</li><li>但版本古老, 我觉得很不好用, 不比命令行操作清晰明了.</li><li>在conda环境中使用apbs</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apbs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-file=1lse_apbs.data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1lse_apbs.in</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1lse_apbs.log</span></span></code></pre></div><ul><li>输出的.dx文件，包含了静电势格点数据，可加载到VMD中可视化</li></ul><h2 id="可视化" tabindex="-1">可视化 <a class="header-anchor" href="#可视化" aria-label="Permalink to &quot;可视化&quot;">​</a></h2><p>可以选择VMD或者pymol进行绘图.</p><h3 id="原子电荷可视化" tabindex="-1">原子电荷可视化 <a class="header-anchor" href="#原子电荷可视化" aria-label="Permalink to &quot;原子电荷可视化&quot;">​</a></h3><ul><li>利用pqr文件中的电荷信息来着色, 展示每个原子上分配的电荷大小.</li><li>效果如图 <ul><li><img src="'+t+'" alt="1736824648945"></li></ul></li><li><a href="http://sobereva.com/365" target="_blank" rel="noreferrer">将GROMACS的原子电荷信息读入VMD的方法</a></li></ul><h3 id="静电势能等势面" tabindex="-1">静电势能等势面 <a class="header-anchor" href="#静电势能等势面" aria-label="Permalink to &quot;静电势能等势面&quot;">​</a></h3><ul><li>效果如图 <ul><li><img src="'+r+'" alt="1736782395327"></li></ul></li></ul><h3 id="静电势表面" tabindex="-1">静电势表面 <a class="header-anchor" href="#静电势表面" aria-label="Permalink to &quot;静电势表面&quot;">​</a></h3><ul><li>全称: 静电势填色的溶剂可及表面图</li><li>即: 将静电势能映射到生物分子的表面</li><li>效果如图 <ul><li><img src="'+p+'" alt="1736782069601"></li></ul></li><li>使用VMD绘制表面静电势图</li><li>待更</li></ul><h2 id="拓展阅读" tabindex="-1">拓展阅读 <a class="header-anchor" href="#拓展阅读" aria-label="Permalink to &quot;拓展阅读&quot;">​</a></h2><ul><li><a href="https://jerkwin.github.io/2017/03/12/%E6%95%B4%E7%90%86-APBS%E6%95%99%E7%A8%8B/" target="_blank" rel="noreferrer">APBS教程|Jerkwin</a></li><li><a href="http://bioms.org/thread-208-1-1.html" target="_blank" rel="noreferrer">VMD配合APBS显示分子表面静电势 - Powered by Discuz!</a></li><li><a href="http://bbs.keinsci.com/thread-24843-1-1.html" target="_blank" rel="noreferrer">如何去理解一个由APBS网页版计算蛋白质静电势得到的.dx文件中的数据？ - 分子模拟 (Molecular Modeling) - 计算化学公社</a></li><li><a href="http://sobereva.com/196" target="_blank" rel="noreferrer">使用Multiwfn结合VMD分析和绘制分子表面静电势分布 - 思想家公社的门口：量子化学·分子模拟·二次元</a></li><li><a href="http://sobereva.com/639" target="_blank" rel="noreferrer">基于原子电荷极快速绘制超大体系的分子表面静电势图 - 思想家公社的门口：量子化学·分子模拟·二次元</a></li><li><a href="http://bbs.keinsci.com/thread-11080-1-1.html" target="_blank" rel="noreferrer">使用Multiwfn+VMD快速地绘制静电势着色的分子范德华表面图和分子间穿透图（含视频） - 计算化学公社</a></li></ul>',27)]))}const F=i(h,[["render",n]]);export{g as __pageData,F as default};
